def find_anagrams(s, p):
    from collections import Counter
    p_count = Counter(p)
    s_count = Counter()
    anagrams = []
    for i in range(len(s)):
        s_count[s[i]] += 1
        if i >= len(p):
            s_count[s[i - len(p)]] -= 1
            if s_count[s[i - len(p)]] == 0:
                del s_count[s[i - len(p)]]
        if i >= len(p) - 1 and s_count == p_count:
            anagrams.append(i - len(p) + 1)
    return sorted(anagrams)
